use std::fs::File;
use std::io::Write;
use std::process::Command;

pub fn create_wb() {
    // create the whitebox from BV-WhiteBox: https://github.com/quarkslab/BVWhiteBox/tree/master

    // https://gchq.github.io/CyberChef/#recipe=To_Hex('None',0)&%%%2BPj4%2BPj4%2BPj4%2BPj4%2BPj4%2BPj4%%2BIDA6CiAgICAgICAgaWYgKHJlc3VsdCArIGkpKioyIDw9IG46CiAgICAgICAgICAgIHJlc3VsdCArPSBpCiAgICAgICAgaSAvLz0gMgogICAgcmV0dXJuIHJlc3VsdAojID4%2BPj4%2BPj4%2BPj4%2BPj4%2BPj4%
    let create_wb_hexa = "";

    let create_wb_bytes = match hex::decode(create_wb_hexa) {
        Ok(bytes) => bytes,
        Err(e) => {
            eprintln!("Failed to decode hex: {:?}", e);
            return;
        }
    };

    let create_wb_code = String::from_utf8_lossy(&create_wb_bytes);

    let mut file = match File::create("create_wb.py") {
        Ok(file) => file,
        Err(e) => {
            eprintln!("Failed to create the whitebox: {:?}", e);
            return;
        }
    };

    if let Err(e) = file.write_all(create_wb_code.as_bytes()) {
        eprintln!("Failed to create the whitebox: {:?}", e);
        return;
    }

    let status = Command::new("python3")
        .arg("create_wb.py")
        .status();

    match status {
        Ok(status) => {
            if !status.success() {
                eprintln!("Failed to create the whitebox: {:?}", status);
            }
        }
        Err(e) => {
            eprintln!("Failed to create the whitebox: {:?}", e);
        }
    }
}
